<div class="en fr pt tr vi">
<svg viewBox="0 0 700 210" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="26" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">Custodial tokenization: real shares stay regulated, tokens go on-chain</text>
  <g font-family="sans-serif">
    <rect x="30" y="70" width="160" height="80" rx="8" fill="#1c1c1f" stroke="#38bdf8" stroke-width="1.5"/>
    <text x="110" y="98" fill="#e4e4e7" font-size="11" font-weight="700" text-anchor="middle">Real shares (IVV·MU)</text>
    <text x="110" y="120" fill="#a1a1aa" font-size="10" text-anchor="middle">Regulated custody chain</text>
    <text x="110" y="138" fill="#71717a" font-size="9" text-anchor="middle">Not moved to blockchain</text>

    <rect x="270" y="70" width="160" height="80" rx="8" fill="#1c1c1f" stroke="#a78bfa" stroke-width="1.5"/>
    <text x="350" y="98" fill="#e4e4e7" font-size="11" font-weight="700" text-anchor="middle">Oasis Pro TA</text>
